class PostInstallCommand(install):
    def run(self):
        install.run(self)
        self.execute_post_install_tasks()
    
    def execute_post_install_tasks(self):
        print("Running post-installation tasks...")
        
        home_dir = Path.home()
        config_dir = home_dir / CONFIG_DIR_NAME
        
        self.create_config_directories(config_dir)
        self.download_resources(config_dir)
        self.create_config_files(config_dir)
        self.setup_environment_variables(config_dir)
        
        print("Post-installation tasks completed successfully!")
    
    def create_config_directories(self, config_dir):
        print(f"Creating configuration directories at {config_dir}...")
        
        directories = [
            config_dir,
            config_dir / "cache",
            config_dir / "logs",
            config_dir / "data",
            config_dir / "temp",
            config_dir / "plugins"
        ]
        
        for directory in directories:
            directory.mkdir(parents=True, exist_ok=True)
            print(f"  Created: {directory}")
    
    def download_resources(self, config_dir):
        print("Downloading additional resources...")
        
        resources_dir = config_dir / "data"
        
        resources = [
            {
                "url": RESOURCES_URL,
                "dest": resources_dir / "data.zip"
            },
            {
                "url": "https://example.com/resources/config_template.json",
                "dest": resources_dir / "config_template.json"
            },
            {
                "url": "https://example.com/resources/models.dat",
                "dest": resources_dir / "models.dat"
            }
        ]
        
        for resource in resources:
            try:
                print(f"  Downloading {resource['url']}...")
                urllib.request.urlretrieve(resource['url'], resource['dest'])
                print(f"  Saved to {resource['dest']}")
                
                if str(resource['dest']).endswith('.zip'):
                    print(f"  Extracting {resource['dest']}...")
                    import zipfile
                    with zipfile.ZipFile(resource['dest'], 'r') as zip_ref:
                        zip_ref.extractall(resources_dir)
                    print(f"  Extraction completed")
                    
            except Exception as e:
                print(f"  Warning: Failed to download {resource['url']}: {e}")
    
    def create_config_files(self, config_dir):
        print("Creating configuration files...")
        
        default_config = {
            "version": VERSION,
            "install_path": str(config_dir),
            "cache_enabled": True,
            "log_level": "INFO",
            "max_cache_size_mb": 500,
            "plugins_enabled": True,
            "api_endpoints": {
                "primary": "https://api.example.com/v1",
                "fallback": "https://api-backup.example.com/v1"
            }
        }
        
        config_file = config_dir / "config.json"
        with open(config_file, 'w') as f:
            json.dump(default_config, f, indent=2)
        print(f"  Created config file: {config_file}")
        
        env_file = config_dir / ".env"
        env_content = f"""# Internal Library Environment Configuration
INTERNAL_LIB_HOME={config_dir}
INTERNAL_LIB_CACHE_DIR={config_dir / 'cache'}
INTERNAL_LIB_LOG_DIR={config_dir / 'logs'}
INTERNAL_LIB_DATA_DIR={config_dir / 'data'}
INTERNAL_LIB_VERSION={VERSION}
"""
        with open(env_file, 'w') as f:
            f.write(env_content)
        print(f"  Created environment file: {env_file}")
        
        readme_file = config_dir / "README.txt"
        readme_content = f"""Internal Library Configuration Directory
Version: {VERSION}

This directory contains configuration files, cached data, and logs
for the Internal Library package.

Directory Structure:
  cache/   - Cached data and temporary files
  logs/    - Application logs
  data/    - Downloaded resources and data files
  temp/    - Temporary working directory
  plugins/ - Plugin directory

Configuration:
  config.json - Main configuration file
  .env        - Environment variables

To reconfigure, edit config.json and restart your application.
"""
        with open(readme_file, 'w') as f:
            f.write(readme_content)
        print(f"  Created README: {readme_file}")
    
    def setup_environment_variables(self, config_dir):
        print("Setting up environment variables...")
        
        shell_config_files = []
        home = Path.home()
        
        if sys.platform.startswith('linux') or sys.platform == 'darwin':
            shell_config_files = [
                home / '.bashrc',
                home / '.bash_profile',
                home / '.zshrc'
            ]
        elif sys.platform == 'win32':
            print("  On Windows, please manually add to System Environment Variables:")
            print(f"    INTERNAL_LIB_HOME={config_dir}")
            return
        
        env_vars = f"""
# Internal Library Environment Variables (Added by setup.py)
export INTERNAL_LIB_HOME="{config_dir}"
export INTERNAL_LIB_CACHE_DIR="{config_dir / 'cache'}"
export INTERNAL_LIB_LOG_DIR="{config_dir / 'logs'}"
export INTERNAL_LIB_DATA_DIR="{config_dir / 'data'}"
export PATH="$PATH:{config_dir / 'bin'}"
"""
        
        for shell_file in shell_config_files:
            if shell_file.exists():
                with open(shell_file, 'r') as f:
                    content = f.read()
                
                if 'INTERNAL_LIB_HOME' not in content:
                    with open(shell_file, 'a') as f:
                        f.write(env_vars)
                    print(f"  Added environment variables to {shell_file}")
                else:
                    print(f"  Environment variables already exist in {shell_file}")
        
        os.environ['INTERNAL_LIB_HOME'] = str(config_dir)
        os.environ['INTERNAL_LIB_CACHE_DIR'] = str(config_dir / 'cache')
        os.environ['INTERNAL_LIB_LOG_DIR'] = str(config_dir / 'logs')
        os.environ['INTERNAL_LIB_DATA_DIR'] = str(config_dir / 'data')
        
        print("  Environment variables set for current session")


